package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ParserConfiguration;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.FieldDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.nodeTypes.NodeWithVariables;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        Path filePath = Paths.get(args[0]);
        String sourceCode = Files.readString(filePath);

        ParserConfiguration config = new ParserConfiguration()
                .setLanguageLevel(ParserConfiguration.LanguageLevel.JAVA_17);
        JavaParser parser = new JavaParser(config);

        ParseResult<CompilationUnit> parseResult = parser.parse(sourceCode);

        if (!parseResult.isSuccessful() || parseResult.getResult().isEmpty()) {
            System.err.println("Failed to parse file: " + parseResult.getProblems());
            System.exit(1);
        }

        CompilationUnit cu = parseResult.getResult().get();

        cu.accept(new TFastFramedTransportTransformer(), null);

        String transformedCode = cu.toString();
        Files.writeString(filePath, transformedCode);

        System.out.println("Transformation completed successfully.");
    }

    static class TFastFramedTransportTransformer extends ModifierVisitor<Void> {

        @Override
        public Visitable visit(ClassOrInterfaceType type, Void arg) {
            if (type.getNameAsString().equals("TFastFramedTransport")) {
                type.setName("TFramedTransport");
            }
            return super.visit(type, arg);
        }

        @Override
        public Visitable visit(ObjectCreationExpr expr, Void arg) {
            if (expr.getType().getNameAsString().equals("TFastFramedTransport")) {
                expr.setType(new ClassOrInterfaceType(null, "TFramedTransport"));

                List<Expression> arguments = expr.getArguments();
                if (arguments.size() == 2) {
                    arguments.remove(1);
                }
            }
            return super.visit(expr, arg);
        }

        @Override
        public Visitable visit(MethodCallExpr expr, Void arg) {
            if (expr.getNameAsString().equals("TFastFramedTransport")) {
                expr.setName("TFramedTransport");
            }
            return super.visit(expr, arg);
        }
    }
}

