          if (bytes.length == 1) {
            throw new TException("Unknown prefixed protocol with byte length 1.");
          }
          switch (bytes[1]) {
            case PrefixedSerializer.COMPACT_PROTOCOL_BYTE:
              transport.reset(bytes, 2, bytes.length - 2);
              base.read(protocol);
              break;
            default:
