     * @param base The object to serialize
     * @return Serialized object in byte[] format
     */
    public byte[] serialize(TBase base) throws TException {
      outputStream.reset();
      outputStream.write(SECRET_BYTE);
      outputStream.write(COMPACT_PROTOCOL_BYTE);
